67	class FunctionDictHelper
68	{
69	public:
70	    explicit FunctionDictHelper(ContextPtr context_) : context(context_) {}
71	
72	    std::shared_ptr<const IDictionary> getDictionary(const String & dictionary_name)
73	    {
74	        auto dict = context->getExternalDictionariesLoader().getDictionary(dictionary_name, context);
75	
76	        if (!access_checked)
77	        {
78	            context->checkAccess(AccessType::dictGet, dict->getDatabaseOrNoDatabaseTag(), dict->getDictionaryID().getTableName());
79	            access_checked = true;
80	        }
81	
82	        return dict;
83	    }
84	
85	    std::shared_ptr<const IDictionary> getDictionary(const ColumnPtr & column)
86	    {
87	        const auto * dict_name_col = checkAndGetColumnConst<ColumnString>(column.get());
88	
89	        if (!dict_name_col)
90	            throw Exception(ErrorCodes::UNSUPPORTED_METHOD, "Expected const String column");
91	
92	        return getDictionary(dict_name_col->getValue<String>());
93	    }
94	
95	    static void checkDictionaryHierarchySupport(const std::shared_ptr<const IDictionary> & dictionary)
96	    {
97	        const auto & dictionary_structure = dictionary->getStructure();
98	        auto hierarchical_attribute_index_optional = dictionary_structure.hierarchical_attribute_index;
99	
100	        if (!dictionary->hasHierarchy() || !hierarchical_attribute_index_optional.has_value())
101	            throw Exception(ErrorCodes::UNSUPPORTED_METHOD,
102	                "Dictionary {} does not support hierarchy",
103	                dictionary->getFullName());
104	    }
105	
106	    static const DictionaryAttribute & getDictionaryHierarchicalAttribute(const std::shared_ptr<const IDictionary> & dictionary)
107	    {
108	        checkDictionaryHierarchySupport(dictionary);
109	
110	        const auto & dictionary_structure = dictionary->getStructure();
111	        auto hierarchical_attribute_index_optional = dictionary_structure.hierarchical_attribute_index;
112	
113	        size_t hierarchical_attribute_index = *hierarchical_attribute_index_optional;
114	        const auto & hierarchical_attribute = dictionary_structure.attributes[hierarchical_attribute_index];
115	
116	        return hierarchical_attribute;
117	    }
118	
119	    bool isDictGetFunctionInjective(const Block & sample_columns)
120	    {
121	        /// Assume non-injective by default
122	        if (sample_columns.empty())
123	            return false;
124	
125	        if (sample_columns.columns() < 3)
126	            throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH, "Wrong arguments count");
127	
128	        const auto * dict_name_col = checkAndGetColumnConst<ColumnString>(sample_columns.getByPosition(0).column.get());
129	        if (!dict_name_col)
130	            throw Exception(ErrorCodes::ILLEGAL_COLUMN, "First argument of function dictGet must be a constant string");
131	
132	        const auto * attr_name_col = checkAndGetColumnConst<ColumnString>(sample_columns.getByPosition(1).column.get());
133	        if (!attr_name_col)
134	            throw Exception(ErrorCodes::ILLEGAL_COLUMN, "Second argument of function dictGet must be a constant string");
135	
136	        const auto & dictionary_name = dict_name_col->getValue<String>();
137	        const auto & attribute_name = attr_name_col->getValue<String>();
138	
139	        return getDictionary(dictionary_name)->isInjective(attribute_name);
140	    }
141	
142	    DictionaryStructure getDictionaryStructure(const String & dictionary_name) const
143	    {
144	        return context->getExternalDictionariesLoader().getDictionaryStructure(dictionary_name, context);
145	    }
146	
147	    const ContextPtr context;
148	
149	private:
150	    /// Access cannot be not granted, since in this case checkAccess() will throw and access_checked will not be updated.
151	    std::atomic<bool> access_checked = false;
152	
153	    /// We must not cache dictionary or dictionary's structure here, because there are places
154	    /// where ExpressionActionsPtr is cached (StorageDistributed caching it for sharding_key_expr and
155	    /// optimize_skip_unused_shards), and if the dictionary will be cached within "query" then
156	    /// cached ExpressionActionsPtr will always have first version of the query and the dictionary
157	    /// will not be updated after reload (see https://github.com/ClickHouse/ClickHouse/pull/16205)
158	};
