161	class FunctionDictHas final : public IFunction
162	{
163	public:
164	    static constexpr auto name = "dictHas";
165	
166	    static FunctionPtr create(ContextPtr context)
167	    {
168	        return std::make_shared<FunctionDictHas>(context);
169	    }
170	
171	    explicit FunctionDictHas(ContextPtr context_) : helper(context_) {}
172	
173	    String getName() const override { return name; }
174	
175	    size_t getNumberOfArguments() const override { return 0; }
176	
177	    bool isVariadic() const override { return true; }
178	
179	    bool isDeterministic() const override { return false; }
180	
181	    bool isSuitableForShortCircuitArgumentsExecution(const DataTypesWithConstInfo & /*arguments*/) const override { return true; }
182	
183	    bool useDefaultImplementationForConstants() const final { return true; }
184	
185	    ColumnNumbers getArgumentsThatAreAlwaysConstant() const final { return {0}; }
186	
187	    DataTypePtr getReturnTypeImpl(const DataTypes & arguments) const override
188	    {
189	        if (arguments.size() < 2)
190	            throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
191	                "Wrong argument count for function {}",
192	                getName());
193	
194	        if (!isString(arguments[0]))
195	            throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
196	                "Illegal type {} of first argument of function {}, expected a string",
197	                arguments[0]->getName(),
198	                getName());
199	
200	        return std::make_shared<DataTypeUInt8>();
201	    }
202	
203	    ColumnPtr executeImpl(const ColumnsWithTypeAndName & arguments, const DataTypePtr & result_type, size_t input_rows_count) const override
204	    {
205	        /** Do not require existence of the dictionary if the function is called for empty columns.
206	          * This is needed to allow successful query analysis on a server,
207	          *  that is the initiator of a distributed query,
208	          *  in the case when the function will be invoked for real data only at the remote servers.
209	          * This feature is controversial and implemented specially
210	          *  for backward compatibility with the case in the Banner System application.
211	          */
212	        if (input_rows_count == 0)
213	            return result_type->createColumn();
214	
215	        String dictionary_name;
216	
217	        if (const auto * name_col = checkAndGetColumnConst<ColumnString>(arguments[0].column.get()))
218	            dictionary_name = name_col->getValue<String>();
219	        else
220	            throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
221	                "Illegal type {} of first argument of function {}, expected a const string.",
222	                arguments[0].type->getName(),
223	                getName());
224	
225	        auto dictionary = helper.getDictionary(dictionary_name);
226	        auto dictionary_key_type = dictionary->getKeyType();
227	        auto dictionary_special_key_type = dictionary->getSpecialKeyType();
228	
229	        const auto & key_column_with_type = arguments[1];
230	        auto key_column = key_column_with_type.column;
231	        auto key_column_type = key_column_with_type.type;
232	
233	        ColumnPtr range_col;
234	        DataTypePtr range_col_type;
235	
236	        if (dictionary_special_key_type == DictionarySpecialKeyType::Range)
237	        {
238	            if (arguments.size() != 3)
239	                throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
240	                    "Wrong argument count for function {} when dictionary has key type range",
241	                    getName());
242	
243	            range_col = arguments[2].column;
244	            range_col_type = arguments[2].type;
245	
246	            if (!(range_col_type->isValueRepresentedByInteger() && range_col_type->getSizeOfValueInMemory() <= sizeof(Int64)))
247	                throw Exception(ErrorCodes::ILLEGAL_COLUMN,
248	                    "Illegal type {} of fourth argument of function {} must be convertible to Int64.",
249	                    range_col_type->getName(),
250	                    getName());
251	        }
252	
253	        Columns key_columns;
254	        DataTypes key_types;
255	
256	        if (dictionary_key_type == DictionaryKeyType::Simple)
257	        {
258	            key_columns = {key_column};
259	            key_types = {key_column_with_type.type};
260	        }
261	        else if (dictionary_key_type == DictionaryKeyType::Complex)
262	        {
263	            /// Functions in external dictionaries_loader only support full-value (not constant) columns with keys.
264	            key_column = key_column->convertToFullColumnIfConst();
265	
266	            if (isTuple(key_column_type))
267	            {
268	                key_columns = assert_cast<const ColumnTuple &>(*key_column).getColumnsCopy();
269	                key_types = assert_cast<const DataTypeTuple &>(*key_column_type).getElements();
270	            }
271	            else
272	            {
273	                size_t keys_size = dictionary->getStructure().getKeysSize();
274	
275	                if (keys_size > 1)
276	                {
277	                    throw Exception(
278	                        ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
279	                        "Third argument of function {} must be tuple when dictionary is complex and key contains more than 1 attribute."
280	                        "Actual type {}.",
281	                        getName(),
282	                        key_column_type->getName());
283	                }
284	
285	                key_columns = {key_column};
286	                key_types = {key_column_type};
287	            }
288	        }
289	
290	        dictionary->convertKeyColumns(key_columns, key_types);
291	
292	        if (dictionary_special_key_type == DictionarySpecialKeyType::Range)
293	        {
294	            key_columns.emplace_back(range_col);
295	            key_types.emplace_back(range_col_type);
296	        }
297	
298	        return dictionary->hasKeys(key_columns, key_types);
299	    }
300	
301	private:
302	    mutable FunctionDictHelper helper;
303	};
