312	/// This variant of function derives the result type automatically.
313	template <DictionaryGetFunctionType dictionary_get_function_type>
314	class FunctionDictGetNoType final : public IFunction
315	{
316	public:
317	    // Kind of gross but we need a static field called "name" for FunctionFactory::registerFunction, and this is the easiest way
318	    static constexpr auto name = (dictionary_get_function_type == DictionaryGetFunctionType::get)
319	        ? "dictGet"
320	        : ((dictionary_get_function_type == DictionaryGetFunctionType::getOrDefault) ? "dictGetOrDefault" : "dictGetAll");
321	
322	    static FunctionPtr create(ContextPtr context)
323	    {
324	        return std::make_shared<FunctionDictGetNoType>(context);
325	    }
326	
327	    explicit FunctionDictGetNoType(ContextPtr context_) : helper(context_) {}
328	
329	    String getName() const override { return name; }
330	
331	    bool isVariadic() const override { return true; }
332	    bool isShortCircuit(ShortCircuitSettings & settings, size_t number_of_arguments) const override
333	    {
334	        if constexpr (dictionary_get_function_type != DictionaryGetFunctionType::getOrDefault)
335	            return false;
336	
337	        /// We execute lazily only last argument with default expression.
338	        for (size_t i = 0; i != number_of_arguments - 1; ++i)
339	            settings.arguments_with_disabled_lazy_execution.insert(i);
340	
341	        settings.enable_lazy_execution_for_common_descendants_of_arguments = false;
342	        settings.force_enable_lazy_execution = false;
343	        return true;
344	    }
345	    bool isSuitableForShortCircuitArgumentsExecution(const DataTypesWithConstInfo & /*arguments*/) const override { return true; }
346	    size_t getNumberOfArguments() const override { return 0; }
347	
348	    bool useDefaultImplementationForConstants() const final { return true; }
349	    bool useDefaultImplementationForNulls() const final { return false; }
350	    ColumnNumbers getArgumentsThatAreAlwaysConstant() const final
351	    {
352	        if constexpr (dictionary_get_function_type == DictionaryGetFunctionType::getAll)
353	            return {0, 1, 3};
354	        else
355	            return {0, 1};
356	    }
357	
358	    bool isDeterministic() const override { return false; }
359	
360	    bool isInjective(const ColumnsWithTypeAndName & sample_columns) const override
361	    {
362	        return helper.isDictGetFunctionInjective(sample_columns);
363	    }
364	
365	    DataTypePtr getReturnTypeImpl(const ColumnsWithTypeAndName & arguments) const override
366	    {
367	        if (arguments.size() < 3)
368	            throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
369	                "Wrong argument count for function {}",
370	                getName());
371	
372	        String dictionary_name;
373	        if (const auto * name_col = checkAndGetColumnConst<ColumnString>(arguments[0].column.get()))
374	            dictionary_name = name_col->getValue<String>();
375	        else
376	            throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
377	                "Illegal type {} of first argument of function {}, expected a const string.",
378	                arguments[0].type->getName(),
379	                getName());
380	
381	        Strings attribute_names = getAttributeNamesFromColumn(arguments[1].column, arguments[1].type);
382	
383	        auto dictionary_structure = helper.getDictionaryStructure(dictionary_name);
384	
385	        DataTypes attribute_types;
386	        attribute_types.reserve(attribute_names.size());
387	        for (auto & attribute_name : attribute_names)
388	        {
389	            /// We're extracting the return type from the dictionary's config, without loading the dictionary.
390	            const auto & attribute = dictionary_structure.getAttribute(attribute_name);
391	            attribute_types.emplace_back(attribute.type);
392	        }
393	
394	        bool key_is_nullable = arguments[2].type->isNullable();
395	        if constexpr (dictionary_get_function_type == DictionaryGetFunctionType::getAll)
396	        {
397	            if (key_is_nullable)
398	                throw Exception(ErrorCodes::UNSUPPORTED_METHOD, "Function {} does not support nullable keys", getName());
399	
400	            // Wrap all the attribute types in Array()
401	            for (auto & attr_type : attribute_types)
402	                attr_type = std::make_shared<DataTypeArray>(attr_type);
403	        }
404	        if (attribute_types.size() > 1)
405	        {
406	            if (key_is_nullable)
407	                throw Exception(ErrorCodes::UNSUPPORTED_METHOD, "Function {} support nullable key only for single dictionary attribute", getName());
408	
409	            return std::make_shared<DataTypeTuple>(attribute_types, attribute_names);
410	        }
411	
412	        if (key_is_nullable)
413	            return makeNullable(attribute_types.front());
414	        return attribute_types.front();
415	    }
416	
417	    ColumnPtr executeImpl(const ColumnsWithTypeAndName & arguments, const DataTypePtr & result_type, size_t input_rows_count) const override
418	    {
419	        if (input_rows_count == 0)
420	            return result_type->createColumn();
421	
422	        String dictionary_name;
423	
424	        if (const auto * name_col = checkAndGetColumnConst<ColumnString>(arguments[0].column.get()))
425	            dictionary_name = name_col->getValue<String>();
426	        else
427	            throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
428	                "Illegal type {} of first argument of function {}, expected a const string.",
429	                arguments[0].type->getName(),
430	                getName());
431	
432	        Strings attribute_names = getAttributeNamesFromColumn(arguments[1].column, arguments[1].type);
433	
434	        auto dictionary = helper.getDictionary(dictionary_name);
435	        auto dictionary_key_type = dictionary->getKeyType();
436	        auto dictionary_special_key_type = dictionary->getSpecialKeyType();
437	
438	        size_t current_arguments_index = 3;
439	
440	        ColumnPtr range_col = nullptr;
441	        DataTypePtr range_col_type = nullptr;
442	
443	        if (dictionary_special_key_type == DictionarySpecialKeyType::Range)
444	        {
445	            if (current_arguments_index >= arguments.size())
446	                throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
447	                    "Number of arguments for function {} doesn't match: passed {} should be {}",
448	                    getName(),
449	                    arguments.size(),
450	                    arguments.size() + 1);
451	
452	            range_col = arguments[current_arguments_index].column;
453	            range_col_type = arguments[current_arguments_index].type;
454	
455	            if (!(range_col_type->isValueRepresentedByInteger() && range_col_type->getSizeOfValueInMemory() <= sizeof(Int64)))
456	                throw Exception(ErrorCodes::ILLEGAL_COLUMN,
457	                    "Illegal type {} of fourth argument of function {} must be convertible to Int64.",
458	                    range_col_type->getName(),
459	                    getName());
460	
461	            ++current_arguments_index;
462	        }
463	
464	        Columns default_cols;
465	        size_t collect_values_limit = std::numeric_limits<size_t>::max();
466	
467	        if (dictionary_get_function_type == DictionaryGetFunctionType::getOrDefault)
468	        {
469	            if (current_arguments_index >= arguments.size())
470	                throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
471	                    "Number of arguments for function {} doesn't match: passed {} should be {}",
472	                    getName(),
473	                    arguments.size(),
474	                    arguments.size() + 1);
475	
476	            const auto & column_before_cast = arguments[current_arguments_index];
477	            const auto * column_function = checkAndGetShortCircuitArgument(column_before_cast.column);
478	            /// If we have shortcircuit (column_function exists), default_cols is empty.
479	            if (!column_function)
480	            {
481	                ColumnWithTypeAndName column_to_cast = {column_before_cast.column->convertToFullColumnIfConst(), column_before_cast.type, column_before_cast.name};
482	
483	                auto result = castColumnAccurate(column_to_cast, result_type);
484	
485	                if (attribute_names.size() > 1)
486	                {
487	                    const auto * tuple_column = checkAndGetColumn<ColumnTuple>(result.get());
488	
489	                    if (!tuple_column)
490	                        throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
491	                            "Wrong argument for function {} default values column must be tuple",
492	                            getName());
493	
494	                    if (tuple_column->tupleSize() != attribute_names.size())
495	                        throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
496	                            "Wrong argument for function {} default values tuple column must contain same column size as requested attributes",
497	                            getName());
498	
499	                    default_cols = tuple_column->getColumnsCopy();
500	                }
501	                else
502	                {
503	                    default_cols.emplace_back(result);
504	                }
505	            }
506	
507	            ++current_arguments_index;
508	        }
509	        else
510	        {
511	            if (dictionary_get_function_type == DictionaryGetFunctionType::getAll && current_arguments_index < arguments.size())
512	            {
513	                auto limit_col = arguments[current_arguments_index].column;
514	                // The getUInt later attempts to cast and throws on a type mismatch, so skip actual type checking here
515	                if (!limit_col || !isColumnConst(*limit_col))
516	                    throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
517	                        "Illegal type {} of fourth argument of function {}. Expected const unsigned integer.",
518	                        arguments[current_arguments_index].type->getName(),
519	                        getName());
520	
521	                collect_values_limit = limit_col->getUInt(0);
522	                ++current_arguments_index;
523	            }
524	
525	            for (size_t i = 0; i < attribute_names.size(); ++i)
526	                default_cols.emplace_back(nullptr);
527	        }
528	
529	        if (current_arguments_index < arguments.size())
530	            throw Exception(ErrorCodes::NUMBER_OF_ARGUMENTS_DOESNT_MATCH,
531	                    "Number of arguments for function {} doesn't match: passed {} should be {}",
532	                    getName(),
533	                    arguments.size(),
534	                    current_arguments_index);
535	
536	        auto key_col_with_type = arguments[2];
537	
538	        bool key_is_only_null = key_col_with_type.type->onlyNull();
539	        if (key_is_only_null)
540	            return result_type->createColumnConstWithDefaultValue(input_rows_count);
541	
542	        bool key_is_nullable = key_col_with_type.type->isNullable();
543	        if (key_is_nullable)
544	            key_col_with_type = columnGetNested(key_col_with_type);
545	
546	        auto key_column = key_col_with_type.column;
547	
548	        Columns key_columns;
549	        DataTypes key_types;
550	
551	        if (dictionary_key_type == DictionaryKeyType::Simple)
552	        {
553	            key_columns = {key_column};
554	            key_types = {key_col_with_type.type};
555	        }
556	        else if (dictionary_key_type == DictionaryKeyType::Complex)
557	        {
558	            /// Functions in external dictionaries_loader only support full-value (not constant) columns with keys.
559	            key_column = key_column->convertToFullColumnIfConst();
560	            DataTypePtr key_column_type = key_col_with_type.type;
561	
562	            if (isTuple(key_column_type))
563	            {
564	                key_columns = assert_cast<const ColumnTuple &>(*key_column).getColumnsCopy();
565	                key_types = assert_cast<const DataTypeTuple &>(*key_column_type).getElements();
566	            }
567	            else
568	            {
569	                size_t keys_size = dictionary->getStructure().getKeysSize();
570	
571	                if (keys_size > 1)
572	                {
573	                    throw Exception(
574	                         ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
575	                         "Third argument of function {} must be tuple when dictionary is complex and key contains more than 1 attribute."
576	                         "Actual type {}.",
577	                         getName(),
578	                         key_col_with_type.type->getName());
579	                }
580	
581	                key_columns = {std::move(key_column)};
582	                key_types = {std::move(key_column_type)};
583	            }
584	        }
585	
586	        dictionary->convertKeyColumns(key_columns, key_types);
587	
588	        if (dictionary_special_key_type == DictionarySpecialKeyType::Range)
589	        {
590	            key_columns.emplace_back(range_col);
591	            key_types.emplace_back(range_col_type);
592	        }
593	
594	        DataTypePtr attribute_type = result_type;
595	        if (key_is_nullable)
596	        {
597	            DataTypes attribute_types;
598	            attribute_types.reserve(attribute_names.size());
599	            for (auto & attribute_name : attribute_names)
600	            {
601	                const auto & attribute = dictionary->getStructure().getAttribute(attribute_name);
602	                attribute_types.emplace_back(attribute.type);
603	            }
604	
605	            attribute_type = attribute_types.front();
606	        }
607	
608	        auto result_column = executeDictionaryRequest(
609	            dictionary, attribute_names, key_columns, key_types, attribute_type, default_cols,
610	            collect_values_limit, arguments[current_arguments_index-1], result_type);
611	
612	        if (key_is_nullable)
613	            result_column = wrapInNullable(result_column, {arguments[2]}, result_type, input_rows_count);
614	
615	        return result_column;
616	    }
617	
618	private:
619	
620	    /// When maskedExecute evaluates a short-circuit argument only on the rows where the
621	    /// dictionary key was not found (mask == 1), it expands the result back to full size by
622	    /// filling mask == 0 rows with NULLs via ColumnNullable::expand. Those rows are about to
623	    /// be overwritten by the dictionary result, but castColumnAccurate rejects the column if
624	    /// it contains any NULLs while casting to a non-Nullable type.
625	    /// This helper clears the spurious null-map bits at mask == 0 positions so the cast only
626	    /// fails when the user-provided default genuinely evaluates to NULL on a row that needs it.
627	    static void clearMaskedNullsBeforeCast(
628	        IColumn & column,
629	        const IColumn::Filter & mask,
630	        const DataTypePtr & result_type)
631	    {
632	        if (result_type->isNullable())
633	            return;
634	
635	        if (auto * nullable = typeid_cast<ColumnNullable *>(&column))
636	        {
637	            auto & null_map = nullable->getNullMapData();
638	            chassert(null_map.size() == mask.size());
639	            for (size_t i = 0; i < null_map.size(); ++i)
640	            {
641	                if (!mask[i])
642	                    null_map[i] = 0;
643	            }
644	            /// Recurse in case nested is e.g. Tuple(Nullable(...)).
645	            clearMaskedNullsBeforeCast(nullable->getNestedColumn(), mask, result_type);
646	        }
647	        else if (auto * tuple_col = typeid_cast<ColumnTuple *>(&column))
648	        {
649	            if (const auto * tuple_type = typeid_cast<const DataTypeTuple *>(result_type.get()))
650	            {
651	                const size_t n = std::min(tuple_col->tupleSize(), tuple_type->getElements().size());
652	                for (size_t col_idx = 0; col_idx < n; ++col_idx)
653	                {
654	                    clearMaskedNullsBeforeCast(
655	                        tuple_col->getColumn(col_idx), mask, tuple_type->getElements()[col_idx]);
656	                }
657	            }
658	        }
659	    }
660	
661	    std::pair<ColumnPtr, ColumnPtr> getDefaultsShortCircuit(
662	        IColumn::Filter && default_mask,
663	        const DataTypePtr & result_type,
664	        const ColumnWithTypeAndName & last_argument) const
665	    {
666	        ColumnWithTypeAndName column_before_cast = last_argument;
667	        maskedExecute(column_before_cast, default_mask);
668	
669	        auto mutable_col = IColumn::mutate(column_before_cast.column->convertToFullColumnIfConst());
670	        clearMaskedNullsBeforeCast(*mutable_col, default_mask, result_type);
671	
672	        ColumnWithTypeAndName column_to_cast = {
673	            std::move(mutable_col),
674	            column_before_cast.type,
675	            column_before_cast.name};
676	
677	        auto cast = IColumn::mutate(castColumnAccurate(column_to_cast, result_type));
678	
679	        auto mask_col = ColumnUInt8::create();
680	        mask_col->getData() = std::move(default_mask);
681	        return {std::move(cast), std::move(mask_col)};
682	    }
683	
684	    void restoreShortCircuitColumn(
685	        ColumnPtr & result_column,
686	        ColumnPtr defaults_column,
687	        ColumnPtr mask_column,
688	        const DataTypePtr & result_type) const
689	    {
690	        auto if_func = FunctionFactory::instance().get("if", helper.context);
691	        ColumnsWithTypeAndName if_args =
692	        {
693	            {mask_column, std::make_shared<DataTypeUInt8>(), {}},
694	            {defaults_column, result_type, {}},
695	            {result_column, result_type, {}},
696	        };
697	
698	        auto rows = mask_column->size();
699	        result_column = if_func->build(if_args)->execute(if_args, result_type, rows, /* dry_run = */ false);
700	    }
