702	
703	    ColumnPtr executeDictionaryRequest(
704	        std::shared_ptr<const IDictionary> & dictionary,
705	        const Strings & attribute_names,
706	        const Columns & key_columns,
707	        const DataTypes & key_types,
708	        const DataTypePtr & attribute_type,
709	        const Columns & default_cols,
710	        size_t collect_values_limit,
711	        const ColumnWithTypeAndName & last_argument,
712	        const DataTypePtr & result_type) const
713	    {
714	        ColumnPtr result;
715	
716	        if (attribute_names.size() > 1)
717	        {
718	            const auto & attribute_tuple_type = assert_cast<const DataTypeTuple &>(*attribute_type);
719	
720	            Columns result_columns;
721	            if constexpr (dictionary_get_function_type == DictionaryGetFunctionType::getAll)
722	            {
723	                result_columns = dictionary->getColumnsAllValues(
724	                    attribute_names, attribute_tuple_type.getElements(), key_columns, key_types, default_cols, collect_values_limit);
725	            }
726	            else if (dictionary_get_function_type == DictionaryGetFunctionType::getOrDefault && default_cols.empty())
727	            {
728	                IColumn::Filter default_mask;
729	                result_columns = dictionary->getColumns(attribute_names, attribute_tuple_type.getElements(), key_columns, key_types, default_mask);
730	
731	                auto [defaults_column, mask_column] =
732	                    getDefaultsShortCircuit(std::move(default_mask), result_type, last_argument);
733	
734	                const auto & tuple_defaults = assert_cast<const ColumnTuple &>(*defaults_column);
735	                const auto & result_tuple_type = assert_cast<const DataTypeTuple &>(*result_type);
736	
737	                for (size_t col = 0; col < result_columns.size(); ++col)
738	                {
739	                    restoreShortCircuitColumn(
740	                        result_columns[col],
741	                        tuple_defaults.getColumnPtr(col),
742	                        mask_column,
743	                        result_tuple_type.getElements()[col]);
744	                }
745	            }
746	            else
747	            {
748	                result_columns = dictionary->getColumns(
749	                    attribute_names, attribute_tuple_type.getElements(), key_columns, key_types, default_cols);
750	            }
751	
752	            result = ColumnTuple::create(std::move(result_columns));
753	        }
754	        else
755	        {
756	            if constexpr (dictionary_get_function_type == DictionaryGetFunctionType::getAll)
757	            {
758	                result = dictionary->getColumnAllValues(
759	                    attribute_names[0], attribute_type, key_columns, key_types, default_cols.front(), collect_values_limit);
760	            }
761	            else if (dictionary_get_function_type == DictionaryGetFunctionType::getOrDefault && default_cols.empty())
762	            {
763	                IColumn::Filter default_mask;
764	                result = dictionary->getColumn(attribute_names[0], attribute_type, key_columns, key_types, default_mask);
765	
766	                auto [defaults_column, mask_column] =
767	                    getDefaultsShortCircuit(std::move(default_mask), attribute_type, last_argument);
768	
769	                restoreShortCircuitColumn(result, defaults_column, mask_column, attribute_type);
770	            }
771	            else
772	            {
773	                result = dictionary->getColumn(
774	                    attribute_names[0], attribute_type, key_columns, key_types, default_cols.front());
775	            }
776	        }
777	
778	        return result;
779	    }
780	
781	    Strings getAttributeNamesFromColumn(const ColumnPtr & column, const DataTypePtr & type) const
782	    {
783	        Strings attribute_names;
784	
785	        if (const auto * name_col = checkAndGetColumnConst<ColumnString>(column.get()))
786	        {
787	            attribute_names.emplace_back(name_col->getValue<String>());
788	        }
789	        else if (const auto * tuple_col_const = checkAndGetColumnConst<ColumnTuple>(column.get()))
790	        {
791	            const ColumnTuple & tuple_col = assert_cast<const ColumnTuple &>(tuple_col_const->getDataColumn());
792	            size_t tuple_size = tuple_col.tupleSize();
793	
794	            if (tuple_size < 1)
795	                throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
796	                    "Tuple second argument of function {} must contain multiple constant string columns", getName());
797	
798	            for (size_t i = 0; i < tuple_col.tupleSize(); ++i)
799	            {
800	                const auto * tuple_column = tuple_col.getColumnPtr(i).get();
801	
802	                const auto * attribute_name_column = checkAndGetColumn<ColumnString>(tuple_column);
803	
804	                if (!attribute_name_column)
805	                    throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
806	                        "Tuple second argument of function {} must contain multiple constant string columns",
807	                        getName());
808	
809	                attribute_names.emplace_back(attribute_name_column->getDataAt(0));
810	            }
811	        }
812	        else
813	        {
814	            throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_ARGUMENT,
815	                "Illegal type {} of second argument of function {}, expected a const string or const tuple of const strings.",
816	                type->getName(),
817	                getName());
818	        }
819	
820	        return attribute_names;
821	    }
822	
823	    mutable FunctionDictHelper helper;
824	};
