963	class FunctionDictGetOrNull final : public IFunction
964	{
965	public:
966	    static constexpr auto name = "dictGetOrNull";
967	
968	    static FunctionPtr create(ContextPtr context)
969	    {
970	        return std::make_shared<FunctionDictGetOrNull>(context);
971	    }
972	
973	    explicit FunctionDictGetOrNull(ContextPtr context_)
974	        : dictionary_get_func_impl(context_)
975	        , dictionary_has_func_impl(context_)
976	    {}
977	
978	    String getName() const override { return name; }
979	
980	private:
981	
982	    size_t getNumberOfArguments() const override { return 0; }
983	
984	    bool isVariadic() const override { return true; }
985	
986	    bool isSuitableForShortCircuitArgumentsExecution(const DataTypesWithConstInfo & /*arguments*/) const override { return true; }
987	
988	    bool useDefaultImplementationForConstants() const override { return true; }
989	
990	    bool useDefaultImplementationForNulls() const override { return false; }
991	
992	    bool isDeterministic() const override { return false; }
993	
994	    ColumnNumbers getArgumentsThatAreAlwaysConstant() const override { return {0, 1}; }
995	
996	    bool isInjective(const ColumnsWithTypeAndName & sample_columns) const override
997	    {
998	        return dictionary_get_func_impl.isInjective(sample_columns);
999	    }
1000	
1001	    DataTypePtr getReturnTypeImpl(const ColumnsWithTypeAndName & arguments) const override
1002	    {
1003	        auto result_type = dictionary_get_func_impl.getReturnTypeImpl(arguments);
1004	
1005	        WhichDataType result_data_type(result_type);
1006	        if (result_data_type.isTuple())
1007	        {
1008	            const auto & data_type_tuple = static_cast<const DataTypeTuple &>(*result_type);
1009	            auto elements_types_copy = data_type_tuple.getElements();
1010	            for (auto & element_type : elements_types_copy)
1011	                element_type = makeNullable(element_type);
1012	
1013	            result_type = std::make_shared<DataTypeTuple>(elements_types_copy, data_type_tuple.getElementNames());
1014	        }
1015	        else
1016	            result_type = makeNullable(result_type);
1017	
1018	        return result_type;
1019	    }
1020	
1021	    ColumnPtr executeImpl(const ColumnsWithTypeAndName & arguments, const DataTypePtr & result_type, size_t input_rows_count) const override
1022	    {
1023	        if (input_rows_count == 0)
1024	            return result_type->createColumn();
1025	
1026	        /** We call dictHas function to get which map is key presented in dictionary.
1027	            For key that presented in dictionary dict has result for that key index value will be 1. Otherwise 0.
1028	            We invert result, and then for key that is not presented in dictionary value will be 1. Otherwise 0.
1029	            This inverted result will be used as null column map.
1030	            After that we call dict get function, by contract for key that are not presented in dictionary we
1031	            return default value.
1032	            We create nullable column from dict get result column and null column map.
1033	
1034	            2 additional implementation details:
1035	            1. Result from dict get can be tuple if client requested multiple attributes we apply such operation on each result column.
1036	            2. If column is already nullable we merge column null map with null map that we get from dict has.
1037	          */
1038	
1039	        auto dict_has_arguments = filterAttributeNameArgumentForDictHas(arguments);
1040	        auto is_key_in_dictionary_column = dictionary_has_func_impl.executeImpl(dict_has_arguments, std::make_shared<DataTypeUInt8>(), input_rows_count);
1041	        auto is_key_in_dictionary_column_mutable = is_key_in_dictionary_column->assumeMutable();
1042	        ColumnVector<UInt8> & is_key_in_dictionary_column_typed = assert_cast<ColumnVector<UInt8> &>(*is_key_in_dictionary_column_mutable);
1043	        PaddedPODArray<UInt8> & is_key_in_dictionary_data = is_key_in_dictionary_column_typed.getData();
1044	        for (auto & key : is_key_in_dictionary_data)
1045	            key = !key;
1046	
1047	        auto dictionary_get_result_type = dictionary_get_func_impl.getReturnTypeImpl(arguments);
1048	        auto dictionary_get_result_column = dictionary_get_func_impl.executeImpl(arguments, dictionary_get_result_type, input_rows_count);
1049	
1050	        ColumnPtr result;
1051	
1052	        WhichDataType dictionary_get_result_data_type(dictionary_get_result_type);
1053	
1054	        /// We need to mutate the result column's null map below (via `addNullMap`).
1055	        /// `IColumn::mutate` performs a deep clone of any shared sub-columns, while
1056	        /// `assumeMutable` only casts away const without checking for sharing.
1057	        /// This matters when the dictionary key argument is `Nullable`: in that case
1058	        /// `FunctionDictGetNoType::executeImpl` calls `wrapInNullable`, which produces a
1059	        /// `ColumnNullable` whose null map shares storage with the input key column's
1060	        /// null map. Mutating that shared null map would corrupt the input column —
1061	        /// see issue #73633 where `dictGetOrNull` with a `Nullable` key column was
1062	        /// silently overwriting other columns in the SELECT projection with `NULL`.
1063	        auto dictionary_get_result_column_mutable = IColumn::mutate(std::move(dictionary_get_result_column));
1064	
1065	        if (dictionary_get_result_data_type.isTuple())
1066	        {
1067	            ColumnTuple & column_tuple = assert_cast<ColumnTuple &>(*dictionary_get_result_column_mutable);
1068	
1069	            const auto & columns = column_tuple.getColumns();
1070	            size_t tuple_size = columns.size();
1071	
1072	            MutableColumns new_columns(tuple_size);
1073	            for (size_t tuple_column_index = 0; tuple_column_index < tuple_size; ++tuple_column_index)
1074	            {
1075	                auto nullable_column_map = ColumnVector<UInt8>::create();
1076	                auto & nullable_column_map_data = nullable_column_map->getData();
1077	                nullable_column_map_data.assign(is_key_in_dictionary_data);
1078	
1079	                auto mutable_column = columns[tuple_column_index]->assumeMutable();
1080	                if (ColumnNullable * nullable_column = typeid_cast<ColumnNullable *>(mutable_column.get()))
1081	                {
1082	                    auto & null_map_data = nullable_column->getNullMapData();
1083	                    addNullMap(null_map_data, is_key_in_dictionary_data);
1084	                    new_columns[tuple_column_index] = std::move(mutable_column);
1085	                }
1086	                else
1087	                    new_columns[tuple_column_index] = ColumnNullable::create(std::move(mutable_column), std::move(nullable_column_map));
1088	            }
1089	
1090	            result = ColumnTuple::create(std::move(new_columns));
1091	        }
1092	        else
1093	        {
1094	            if (ColumnNullable * nullable_column = typeid_cast<ColumnNullable *>(dictionary_get_result_column_mutable.get()))
1095	            {
1096	                auto & null_map_data = nullable_column->getNullMapData();
1097	                addNullMap(null_map_data, is_key_in_dictionary_data);
1098	                result = std::move(dictionary_get_result_column_mutable);
1099	            }
1100	            else
1101	            {
1102	                result = ColumnNullable::create(std::move(dictionary_get_result_column_mutable), std::move(is_key_in_dictionary_column_mutable));
1103	            }
1104	        }
1105	
1106	        return result;
1107	    }
1108	
1109	    static void addNullMap(PaddedPODArray<UInt8> & null_map, PaddedPODArray<UInt8> & null_map_to_add)
1110	    {
1111	        chassert(null_map.size() == null_map_to_add.size());
1112	
1113	        for (size_t i = 0; i < null_map.size(); ++i)
1114	            null_map[i] = null_map[i] || null_map_to_add[i];
